   131→func TestFetch_StaleOnNetworkError(t *testing.T) {
   132→	skipIfNoXZ(t)
   133→
   134→	want := "stale,data\n1,2\n"
   135→
   136→	// Server that works for the first request.
   137→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   138→		w.WriteHeader(http.StatusOK)
   139→		_, _ = w.Write([]byte(want))
   140→	}))
   141→
   142→	dir := t.TempDir()
   143→	f := fetch.New(dir)
   144→	cfg := fetch.FetchConfig{Name: "stale", URL: srv.URL, Format: "csv"}
   145→
   146→	// Prime the cache.
   147→	rc, err := f.Fetch(context.Background(), cfg)
   148→	if err != nil {
   149→		t.Fatalf("prime Fetch: %v", err)
   150→	}
   151→	rc.Close()
   152→
   153→	// Shut down the server to simulate network failure.
   154→	srv.Close()
   155→
   156→	// Point to an unreachable address; expect stale fallback.
   157→	cfg.URL = "http://127.0.0.1:1/does-not-exist"
   158→	rc2, err := f.Fetch(context.Background(), cfg)
   159→	if err != nil {
   160→		t.Fatalf("stale Fetch: %v", err)
   161→	}
   162→	defer rc2.Close()
   163→
   164→	got, _ := io.ReadAll(rc2)
   165→	if string(got) != want {
   166→		t.Errorf("stale content: got %q, want %q", got, want)
   167→	}
   168→}
